+
+        // Direct MouseUp (no preceding Down) should still route as a click.
+        let up = MouseEvent::new(MouseEventKind::Up(MouseButton::Left), 1, 0);
+        let result = app.dispatch_mouse(&up);
+        assert_eq!(result, MouseDispatchResult::Consumed);
